import { useState } from 'react';
import { Briefcase, BookOpen, ExternalLink } from 'lucide-react';
import SectionHeader from './SectionHeader';

const experiences = [
  {
    type: 'internship',
    date: 'Sep 2025 · 5 Days',
    role: 'Banking Intern',
    org: 'Commercial International Bank (CIB)',
    location: 'Asyut',
    desc: 'Selected for branch internship based on outstanding online performance. Hands-on experience in banking operations and customer service.',
    logo: 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/CIB_logo.svg/200px-CIB_logo.svg.png',
    logoFallback: '🏦',
  },
  {
    type: 'internship',
    date: 'Jul 2025 · 2 Weeks',
    role: 'Industrial Intern',
    org: 'Asyut Oil Refining Co. (ASORC)',
    location: 'Asyut',
    desc: 'Trained in petroleum refining operations, industrial safety, and collaborated with senior engineers.',
    logoFallback: '🏭',
  },
  {
    type: 'internship',
    date: 'Aug 2024 · 2 Weeks',
    role: 'Marketing Intern',
    org: 'Nile Petroleum Marketing Co.',
    location: 'Asyut',
    desc: 'Blended theoretical + practical marketing training with a cross-functional team.',
    logoFallback: '⛽',
  },
  {
    type: 'training',
    date: 'Aug 2025',
    role: 'Online Training Program',
    org: 'CIB × SAS × Udemy',
    location: 'Online',
    desc: 'Trustworthy AI (SAS) · Customer Centricity (Udemy) · Sustainability Foundations (LinkedIn Learning)',
    logoFallback: '📚',
  },
  {
    type: 'training',
    date: 'Jul 2025',
    role: 'Maharat Digital Marketing',
    org: 'Banque Misr × Google',
    location: 'Online',
    desc: 'Completed "Maharat min Google" — Digital Marketing Fundamentals & online business strategies.',
    logo: 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2f/Google_2015_logo.svg/200px-Google_2015_logo.svg.png',
    logoFallback: '🌐',
  },
  {
    type: 'training',
    date: 'Oct 2024',
    role: 'Digital Business Services Sim',
    org: 'HSBC × Forage',
    location: 'Online',
    desc: 'Developed carbon-neutrality roadmaps, sustainability initiatives, and data-driven PM recommendations.',
    logoFallback: '💼',
  },
];

export default function Experience() {
  const [filter, setFilter] = useState('all');
  const filtered = filter === 'all' ? experiences : experiences.filter(e => e.type === filter);

  return (
    <section id="experience" className="py-24 px-[5%] bg-cream">
      <SectionHeader tag="Career" title='Experience & <em class="italic text-teal not-italic font-serif-display">Training</em>' />

      {/* Filter tabs */}
      <div className="flex gap-2 mb-10">
        {[['all','All'],['internship','Internships'],['training','Training']].map(([val,label]) => (
          <button key={val} onClick={() => setFilter(val)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all ${filter===val ? 'bg-ink text-parchment' : 'bg-parchment text-muted2 hover:text-ink border border-ink/10'}`}>
            {label}
          </button>
        ))}
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        {filtered.map((e, i) => (
          <div key={i}
            className={`reveal ${i%2===1?'delay-1':''} bg-parchment rounded-2xl p-6 border-[1.5px] border-transparent shadow-sm transition-all hover:border-${e.type==='internship'?'amber':'teal'}/20 hover:-translate-y-1 hover:shadow-md`}>
            <div className="flex items-start gap-4">
              {/* Logo / fallback */}
              <div className="w-12 h-12 rounded-xl bg-cream flex items-center justify-center flex-shrink-0 overflow-hidden border border-ink/[.06]">
                {e.logo
                  ? <img src={e.logo} alt={e.org} className="w-8 h-8 object-contain" onError={ev => { ev.target.style.display='none'; ev.target.nextSibling.style.display='block'; }} />
                  : null}
                <span className={e.logo ? 'hidden text-xl' : 'text-xl'}>{e.logoFallback}</span>
              </div>

              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-1">
                  <span className={`inline-flex items-center gap-1 text-[.6rem] font-semibold tracking-wider uppercase px-2 py-0.5 rounded-full ${e.type==='internship'?'bg-amber/10 text-amber2':'bg-teal/10 text-teal2'}`}>
                    {e.type === 'internship' ? <Briefcase size={9}/> : <BookOpen size={9}/>}
                    {e.type === 'internship' ? 'Internship' : 'Training'}
                  </span>
                  <span className="text-[.65rem] text-muted">{e.date}</span>
                </div>
                <h3 className="font-semibold text-[.95rem] text-ink2 leading-tight">{e.role}</h3>
                <p className="text-[.78rem] text-muted mt-0.5 mb-2">{e.org} · {e.location}</p>
                <p className="text-[.84rem] text-muted2 leading-[1.7]">{e.desc}</p>
              </div>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
